CREATE TABLE `user` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `create_time` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) COMMENT '创建时间',
  `modify_time` datetime(6) DEFAULT NULL COMMENT '修改时间',
  `version` int(11) NOT NULL DEFAULT '1' COMMENT '版本号',
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除： true 删除 false 未删除',
  `creator_id` bigint(20) unsigned DEFAULT NULL COMMENT '创建人id @link user.id',
  `creator_username` varchar(20) NOT NULL COMMENT '创建人',
  `modifier_id` bigint(20) unsigned DEFAULT NULL COMMENT '修改人id @link user.id',
  `modifier_username` varchar(20) DEFAULT NULL COMMENT '修改人',
  `enabled` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否启用： true 启用 false 禁用',
  `username` varchar(20) NOT NULL COMMENT '用户账号',
  `nickname` varchar(50) DEFAULT NULL COMMENT '称呼',
  `user_type_id` bigint(20) unsigned NOT NULL COMMENT '用户类型ID @link user_type.id',
  `password` varchar(255) NOT NULL COMMENT '密码',
  `ip_limitable` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否限制ip: true表示是，false表示否',
  `tenant_id` bigint(20) unsigned DEFAULT NULL COMMENT '所属商户ID @link user_type.id；userType为运营人员、商户老板时此字段为空；其它类型需有值；',
  `tenant_manage_id` bigint(20) unsigned DEFAULT NULL COMMENT '所属商户ID @link tenant_manage.id；userType为商户老板时需有值，其他为空',
  `u_key_check` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否启用u盾验证:true:启用,false关闭',
  `u_key_refresh_duration` int(11) NOT NULL DEFAULT '600' COMMENT 'u盾刷新时间(秒)',
  `google_check` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否启用: true表示是，false表示否',
  `google_key` varchar(255) NOT NULL DEFAULT '' COMMENT '谷歌身份验证密钥',
  `max_total_num` int(11) NOT NULL DEFAULT '0' COMMENT '私海库总计最大值 ',
  `max_day_num` int(11) NOT NULL DEFAULT '0' COMMENT '私海每日最大值 ',
  `wechat_account` varchar(150) DEFAULT NULL,
  `wechat_qr_url` varchar(225) DEFAULT NULL COMMENT '微信图片二维码地址',
  `decrypt_flag` tinyint(1) DEFAULT '0' COMMENT '导出脱敏权限是否开启',
  `dialog_decrypt_flag` tinyint(1) DEFAULT '0' COMMENT '弹窗手机号邮箱脱敏权限是否开启',
  `rate` decimal(18,2) DEFAULT NULL COMMENT '费率（不带%，真实费率需要除以100）  取值0-10000之间',
  `cid` int(20) DEFAULT NULL COMMENT '渠道ID(仅针对渠道管理员此字段有值)',
  `app_login_limit` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'app登录权限: true表示是，false表示否',
  `remark` varchar(255) NOT NULL DEFAULT '' COMMENT '备注',
  `status` tinyint(2) NOT NULL DEFAULT '1' COMMENT '审核状态：1、正常，2、弃用',
  `contact_remark` varchar(255) DEFAULT NULL COMMENT '联系备注',
  `auto_disable_num` int(11) NOT NULL DEFAULT '0' COMMENT '自动禁用触发次数',
  `auto_logout_period` int(11) NOT NULL DEFAULT '0' COMMENT '自动登出时间(秒)',
  `pwd_level` int(11) NOT NULL DEFAULT '1' COMMENT '密码强度等级  1:一级密码 2:二级密码 3:三级密码...',
  `apply_audit_limit` int(11) DEFAULT NULL COMMENT '提现私海待审核上限',
  `audit_custom_biz_code` varchar(200) DEFAULT 'riskSmallAmount;normalLargeAmount;auditSecondLargeAmount;unRiskSmallAmount' COMMENT '提现审核单可审核的自定义类别，多个编码分号隔开',
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=2890 DEFAULT CHARSET=utf8mb4 COMMENT='用户';

