  `regist_ip` varchar(255) NOT NULL DEFAULT '' COMMENT '注册IP',
  `regist_address` varchar(255) NOT NULL DEFAULT '' COMMENT '注册地址（IP归属地）',
  `channel_id` bigint(20) DEFAULT NULL COMMENT '渠道ID, @link channel.id',
  `follower_id` bigint(20) DEFAULT NULL COMMENT '所属业务员ID, @link user.id',
  `email` varchar(255) NOT NULL DEFAULT '' COMMENT '邮箱',
  `wechat` varchar(255) NOT NULL DEFAULT '' COMMENT '微信号',
  `agentable` int(4) NOT NULL DEFAULT '0' COMMENT '是否代理：0否，1是',
  `rate_agent_id` bigint(20) DEFAULT NULL COMMENT '占成代理ID',
  `rebate_agent_id` bigint(20) DEFAULT '0' COMMENT '洗码代理ID',
  `channel_partner_id` bigint(20) DEFAULT NULL COMMENT '所属渠道商ID',
  `sex` int(4) NOT NULL DEFAULT '0' COMMENT '性别：0女，1男',
  `birthday` int(11) NOT NULL DEFAULT '0' COMMENT '生日（时间戳）',
  `mobile_checked` int(4) NOT NULL DEFAULT '0' COMMENT '手机号是否验证',
  `enabled` int(4) NOT NULL DEFAULT '0' COMMENT '是否启用：0禁用，1启用',
  `device_key` varchar(255) NOT NULL DEFAULT '' COMMENT '注册设备指纹Key',
  `first_auto_regist` int(4) NOT NULL DEFAULT '0' COMMENT '是否首次自动注册：0否，1是',
  `mobile_area_code` varchar(255) NOT NULL DEFAULT '' COMMENT '手机区号',
  `checked_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '手机验证时间',
  `type` int(4) NOT NULL DEFAULT '0' COMMENT '会员类型',
  `agent_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '成为代理时间',
  `regist_domain` varchar(255) NOT NULL DEFAULT '' COMMENT '注册域名',
  `s_create_time` datetime NOT NULL DEFAULT '1970-01-01 08:00:00' COMMENT '分区字段（同步创建时间）',
  `mobile_attribution` varchar(255) NOT NULL DEFAULT '' COMMENT '手机号归属地',
  `password` varchar(255) DEFAULT NULL COMMENT '密码',
  `speed_transfer_type` tinyint(2) NOT NULL DEFAULT '1' COMMENT '自动免转类型：0,关闭 1,开启',
  `link_id` bigint(20) DEFAULT NULL COMMENT '推广链接ID',
  `premium_show_flag` tinyint(1) DEFAULT '1' COMMENT '是否展示高级代理入口：true 是；false 否',
  `agent_level` int(11) DEFAULT NULL COMMENT '代理层级',
  `limit_value` bigint(20) DEFAULT NULL COMMENT '会员状态(用位表示多种状态组合)',
  PRIMARY KEY (`id`) /*T![clustered_index] NONCLUSTERED */,
  KEY `idx_create_time` (`create_time`),
  KEY `idx_channel_id` (`channel_id`),
  KEY `idx_tenant_plat_id` (`tenant_plat_id`),
  KEY `idx_rebate_agent_id` (`rebate_agent_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin;

CREATE TABLE `dwd_order_deposit` (
  `id` bigint(20) NOT NULL DEFAULT '0' COMMENT '主键ID',
  `create_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '创建时间',
  `modify_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '修改时间',
  `version` int(11) NOT NULL DEFAULT '0' COMMENT '版本号',
  `deleted` int(4) NOT NULL DEFAULT '0' COMMENT '是否删除：0未删除，1已删除',
  `tenant_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '商户ID, @link user.id',
  `tenant_plat_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '商户平台ID, @link tenant_plat.id',
  `player_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '玩家ID, @link player.id',
  `player_username` varchar(255) NOT NULL DEFAULT '' COMMENT '玩家账号, @link player.username',
  `status` int(4) NOT NULL DEFAULT '0' COMMENT '订单状态：1待支付，2支付成功，3支付失败，4已撤销',
  `amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '交易金额',
  `channel_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '渠道ID, @link channel.id',
  `pay_type_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '支付类型ID, @link pay_type.id',
  `pay_mode_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '支付方式ID, @link pay_mode.id',
  `third_order_no` varchar(255) NOT NULL DEFAULT '' COMMENT '三方订单号',
  `third_trade_date` varchar(255) NOT NULL DEFAULT '' COMMENT '三方交易日期',
  `actual_amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '实际到账金额',
  `device` int(4) NOT NULL DEFAULT '0' COMMENT '设备类型',
  `finished_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '完成时间',
  `remark` varchar(255) NOT NULL DEFAULT '' COMMENT '备注',
  `bank_transfer_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '银行转账ID',
  `times` int(11) NOT NULL DEFAULT '0' COMMENT '充值次数',
  `callback_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '回调时间',
  `operate_remark` varchar(255) NOT NULL DEFAULT '' COMMENT '操作备注',
  `amount_before` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '交易前余额',
  `amount_after` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '交易后余额',
  `regist_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '注册时间',
  `pay_account_change_log_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '资金变更日志ID, @link pay_account_change_log.id',
  `ip` varchar(255) NOT NULL DEFAULT '' COMMENT 'IP地址',
  `pay_type_group_name` varchar(255) NOT NULL DEFAULT '' COMMENT '支付类型分组名称',
  `pay_acct_name` varchar(255) NOT NULL DEFAULT '' COMMENT '收款账户名',
  `pay_acct_no` varchar(255) NOT NULL DEFAULT '' COMMENT '收款账号',
  `pay_bank_name` varchar(255) NOT NULL DEFAULT '' COMMENT '收款银行名称',
  `s_create_time` datetime NOT NULL DEFAULT '1970-01-01 08:00:00' COMMENT '分区字段（同步创建时间）',
  `origin_sign` varchar(1024) DEFAULT NULL COMMENT '签名信息',
  `vip_id` bigint(20) DEFAULT NULL COMMENT '会员等级ID, @link vip.id',
  PRIMARY KEY (`id`) /*T![clustered_index] NONCLUSTERED */,
  KEY `idx_player_id` (`player_id`),
  KEY `idx_finished_time` (`finished_time`),
  KEY `idx_tenant_plat_id` (`tenant_plat_id`),
  KEY `idx_callback_time` (`callback_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin;

CREATE TABLE `dwd_order_withdrawal` (
  `id` bigint(20) NOT NULL DEFAULT '0' COMMENT '主键ID',
  `create_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '创建时间',
  `modify_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '修改时间',
  `version` int(11) NOT NULL DEFAULT '0' COMMENT '版本号',
  `deleted` int(4) NOT NULL DEFAULT '0' COMMENT '是否删除：0未删除，1已删除',
  `auditor_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '审核人ID',
  `tenant_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '商户ID',
  `tenant_plat_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '商户平台ID, @link tenant_plat.id',
  `player_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '玩家ID, @link player.id',
  `player_username` varchar(255) NOT NULL DEFAULT '' COMMENT '玩家账号, @link player.username',
  `status` int(4) NOT NULL DEFAULT '0' COMMENT '订单状态',
  `amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '交易金额',
  `channel_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '渠道ID, @link channel.id',
  `account_name` varchar(255) NOT NULL DEFAULT '' COMMENT '提款账户名',
  `account_no` varchar(255) NOT NULL DEFAULT '' COMMENT '提款账号',
  `bank_name` varchar(255) NOT NULL DEFAULT '' COMMENT '银行名称',
  `bank_province` varchar(255) NOT NULL DEFAULT '' COMMENT '开户省份',
  `bank_city` varchar(255) NOT NULL DEFAULT '' COMMENT '开户城市',
  `bank_address` varchar(255) NOT NULL DEFAULT '' COMMENT '开户支行地址',
  `third_order_no` varchar(255) NOT NULL DEFAULT '' COMMENT '三方订单号',
  `third_trade_date` varchar(255) NOT NULL DEFAULT '' COMMENT '三方交易日期',
  `follower_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '所属业务员ID, @link user.id',
  `finished_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '完成时间',
  `remark` varchar(255) NOT NULL DEFAULT '' COMMENT '备注',
  `times` int(11) NOT NULL DEFAULT '0' COMMENT '提款次数',
  `device` int(4) NOT NULL DEFAULT '0' COMMENT '设备类型',
  `callback_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '回调时间',
  `callback_remark` varchar(255) NOT NULL DEFAULT '' COMMENT '回调备注',
  `audit_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '审核时间',
  `audit_remark` varchar(255) NOT NULL DEFAULT '' COMMENT '审核备注',
  `operate_remark` varchar(255) NOT NULL DEFAULT '' COMMENT '操作备注',
  `amount_before` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '交易前余额',
  `amount_after` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '交易后余额',
  `ip` varchar(255) NOT NULL DEFAULT '' COMMENT 'IP地址',
  `pay_account_change_log_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '资金变更日志ID, @link pay_account_change_log.id',
  `pay_mode_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '支付方式ID, @link pay_mode.id',
  `withdrawal_type_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '提款类型ID, @link withdrawal_type.id',
  `receive_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '领取时间',
  `split_flag` int(4) NOT NULL DEFAULT '0' COMMENT '是否拆单',
  `main_order_no` bigint(20) NOT NULL DEFAULT '0' COMMENT '主订单号',
  `fee_amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '手续费金额',
  `act_amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '实际到账金额（扣除手续费后）',
  `audit_step` int(11) NOT NULL DEFAULT '0' COMMENT '当前审核步骤',
  `audit_times` int(11) NOT NULL DEFAULT '0' COMMENT '审核次数',
  `audit_amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '审核金额',
  `risk_status` int(4) NOT NULL DEFAULT '0' COMMENT '风控状态：0正常，1风险',
  `order_risk_type` int(4) NOT NULL DEFAULT '0',
  `ip_attribution` int(11) DEFAULT NULL COMMENT '是否常用IP归属地，0，判断失败，不处理，1:是常用，2非常用',
  `withdrawal_type` int(4) NOT NULL DEFAULT '1' COMMENT '提款类型：1:普通提现 2:一键挂单',
  `vip_id` bigint(20) DEFAULT NULL COMMENT '会员等级ID, @link vip.id',
  `reserve_flag` tinyint(1) DEFAULT NULL COMMENT '是否预约提款',
  `reserve_hour` int(11) DEFAULT NULL COMMENT '预约提款时限',
  `risk_event_code` bigint(20) DEFAULT NULL COMMENT '风险事件标识',
  `s_create_time` datetime NOT NULL DEFAULT '1970-01-01 08:00:00' COMMENT '分区字段（同步创建时间）',
  PRIMARY KEY (`id`) /*T![clustered_index] NONCLUSTERED */,
  KEY `idx_callback_time` (`callback_time`),
  KEY `idx_finished_time` (`finished_time`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin;

CREATE TABLE `dwd_order_rebate` (
  `id` bigint(20) NOT NULL DEFAULT '0' COMMENT '主键ID',
  `create_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '创建时间',
  `modify_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '修改时间',
  `version` int(11) NOT NULL DEFAULT '0' COMMENT '版本号',
  `deleted` int(4) NOT NULL DEFAULT '0' COMMENT '是否删除：0未删除，1已删除',
  `auditor_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '审核人ID, @link user.id',
  `tenant_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '商户ID, @link user.id',
  `tenant_plat_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '商户平台ID, @link tenant_plat.id',
  `player_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '玩家ID, @link player.id',
  `player_username` varchar(255) NOT NULL DEFAULT '' COMMENT '玩家账号, @link player.username',
  `status` int(4) NOT NULL DEFAULT '0' COMMENT '订单状态',
  `amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '交易金额',
  `channel_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '渠道ID, @link channel.id',
  `biz_date` date DEFAULT NULL COMMENT '业务日期',
  `bet_num` int(11) NOT NULL DEFAULT '0' COMMENT '投注笔数',
  `bet_amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '投注金额',
  `valid_bet_amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '有效投注金额',
  `win_amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '玩家输赢金额',
  `order_agent_rebate_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '代理洗码返水配置ID',
  `vip_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '会员等级ID, @link vip.id',
  `operate_remark` varchar(255) NOT NULL DEFAULT '' COMMENT '操作备注',
  `amount_before` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '交易前余额',
  `amount_after` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '交易后余额',
  `rebate_bet_amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '参与计算返水的投注金额',
  `type` int(4) NOT NULL DEFAULT '0' COMMENT '类型',
  `rebate_type` int(4) NOT NULL DEFAULT '0' COMMENT '返水类型',
  `receive_ip` varchar(255) NOT NULL DEFAULT '' COMMENT '领取IP',
  `receive_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '领取时间',
  `start_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '统计开始时间',
  `end_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '统计结束时间',
  `s_create_time` datetime NOT NULL DEFAULT '1970-01-01 08:00:00' COMMENT '分区字段（同步创建时间）',
  PRIMARY KEY (`id`) /*T![clustered_index] NONCLUSTERED */,
  KEY `idx_modify_time` (`modify_time`),
  KEY `idx_tenant_plat_id` (`tenant_plat_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin;

