CREATE TABLE `dwd_order_vip_award` (
  `id` bigint(20) unsigned NOT NULL COMMENT 'ID',
  `create_time` datetime(6) NOT NULL COMMENT '创建时间',
  `modify_time` datetime(6) DEFAULT NULL COMMENT '修改时间',
  `version` int(11) NOT NULL DEFAULT '1' COMMENT '版本号',
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除： true 删除 false 未删除',
  `tenant_id` bigint(20) unsigned NOT NULL DEFAULT '0' COMMENT '商户ID, @link user.id',
  `tenant_plat_id` bigint(20) unsigned NOT NULL DEFAULT '0' COMMENT '商户平台ID, @link tenant_plat.id',
  `player_id` bigint(20) unsigned NOT NULL COMMENT '玩家ID @link player.id ',
  `player_username` varchar(255) DEFAULT NULL COMMENT '玩家账号 @link player.username ',
  `status` tinyint(2) NOT NULL COMMENT '订单状态 ',
  `amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '交易金额',
  `channel_id` bigint(20) unsigned DEFAULT NULL COMMENT '所属渠道ID  @link channel.id ',
  `operate_remark` varchar(255) DEFAULT NULL COMMENT '操作备注',
  `amount_before` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '交易前金额',
  `amount_after` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '交易后金额',
  `type` tinyint(4) NOT NULL COMMENT '类型',
  `vip_id` bigint(20) NOT NULL COMMENT '相关vip的ID @link Vip.id',
  `year` int(11) DEFAULT NULL COMMENT '年度（如：2021）',
  `stage_num` tinyint(4) DEFAULT NULL COMMENT '阶段值',
  `s_create_time` datetime NOT NULL DEFAULT '1970-01-01 08:00:00' COMMENT '分区字段（同步创建时间）',
  PRIMARY KEY (`id`) /*T![clustered_index] CLUSTERED */
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin COMMENT='VIP礼金订单';

CREATE TABLE `dwd_order_activity` (
