  `operate_remark` varchar(255) NOT NULL DEFAULT '' COMMENT '操作备注',
  `amount_before` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '交易前余额',
  `amount_after` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '交易后余额',
  `award_send_type` int(4) NOT NULL DEFAULT '0' COMMENT '发放方式',
  `task_type` int(4) NOT NULL DEFAULT '0' COMMENT '任务类型',
  `receive_ip` varchar(255) NOT NULL DEFAULT '' COMMENT '领取IP',
  `receive_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '领取时间',
  `stage_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '阶段ID',
  `auditor_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '审核人ID, @link user.id',
  `audit_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '审核时间',
  `receive_end_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '领取截止时间',
  `second_auditor_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '二审审核人ID, @link user.id',
  `second_audit_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '二审审核时间',
  `second_audit_remark` varchar(255) NOT NULL DEFAULT '' COMMENT '二审审核备注',
  `activity_award_sub_type` int(11) NOT NULL DEFAULT '0' COMMENT '活动奖励子类型',
  `cycle_award_rounds` int(11) NOT NULL DEFAULT '0' COMMENT '周期奖励轮次',
  `s_create_time` datetime NOT NULL DEFAULT '1970-01-01 08:00:00' COMMENT '分区字段（同步创建时间）',
  PRIMARY KEY (`id`) /*T![clustered_index] NONCLUSTERED */,
  KEY `idx_tenant_plat_id` (`tenant_plat_id`),
  KEY `idx_modify_time` (`modify_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin;

