CREATE TABLE `dwd_bet_order` (
  `id` bigint(20) NOT NULL DEFAULT '0' COMMENT '主键ID',
  `create_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '创建时间',
  `modify_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '修改时间',
  `version` int(11) NOT NULL DEFAULT '0' COMMENT '版本号',
  `deleted` int(4) NOT NULL DEFAULT '0' COMMENT '是否删除：0未删除，1已删除',
  `bet_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '下注时间',
  `settle_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '结算时间',
  `tenant_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '商户ID, @link user.id',
  `tenant_plat_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '商户平台ID, @link tenant_plat.id',
  `player_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '玩家ID, @link player.id',
  `game_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '游戏ID, @link game.id',
  `game_name` text DEFAULT NULL COMMENT '游戏名称',
  `game_line_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '游戏线路ID, @link game_line.id',
  `game_line_series_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '游戏线路系列ID, @link game_line_series.id',
  `game_type_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '游戏类型ID, @link game_type.id',
  `channel_id` bigint(20) NOT NULL DEFAULT '0' COMMENT '渠道ID, @link channel.id',
  `rebate_agent_id` bigint(20) DEFAULT NULL COMMENT '洗码代理ID, @link user.id',
  `third_order_no` varchar(255) NOT NULL DEFAULT '' COMMENT '三方订单号',
  `settle_status` int(4) NOT NULL DEFAULT '0' COMMENT '结算状态',
  `bet_amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '投注金额',
  `win_loss_amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '玩家输赢金额',
  `valid_bet_amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '有效投注金额',
  `extend_valid_bet_amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '真人棋牌扩展表有效投注',
  `extend_win_loss_amount` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '真人棋牌扩展表玩家输赢',
  `insurance_bet` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '真人棋牌投保额',
  `insurance_win` decimal(19,4) NOT NULL DEFAULT '0.0000' COMMENT '真人棋牌保险盈利',
  `take` decimal(19,4) NOT NULL COMMENT '真人棋牌抽水',
  `bet_content` text DEFAULT NULL COMMENT '投注内容',
  `rebated` int(4) NOT NULL DEFAULT '0' COMMENT '是否已计算洗码',
  `bet_game_type_id` bigint(20) DEFAULT NULL COMMENT '投注游戏类型ID, @link game_type.id',
  `batch_no` varchar(255) NOT NULL DEFAULT '' COMMENT '批次号（同步批次）',
  `s_create_time` datetime(6) NOT NULL DEFAULT '1970-01-01 08:00:00.000000' COMMENT '分区字段（同步创建时间）',
  PRIMARY KEY (`id`,`settle_time`) /*T![clustered_index] CLUSTERED */,
  KEY `idx_player_id` (`player_id`),
  UNIQUE KEY `uni_game_line_id_and_third_order_no` (`settle_time`,`game_line_id`,`third_order_no`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin;

 CREATE TABLE `tenant_plat` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID 从1 开始，1,2,3...',
  `create_time` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) COMMENT '创建时间',
  `modify_time` datetime(6) DEFAULT NULL COMMENT '修改时间',
  `version` int(11) NOT NULL DEFAULT '1' COMMENT '版本号',
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除： true 删除 false 未删除',
  `creator_id` bigint(20) unsigned NOT NULL COMMENT '创建人ID, @link user.id',
  `creator_username` varchar(20) NOT NULL COMMENT '创建人, @link user.username',
  `modifier_id` bigint(20) unsigned DEFAULT NULL COMMENT '修改人ID, @link user.id',
  `modifier_username` varchar(20) DEFAULT NULL COMMENT '修改人, @link user.username',
  `name` varchar(15) NOT NULL COMMENT '平台名称',
  `status` tinyint(2) NOT NULL DEFAULT '1' COMMENT '平台申请状态',
  `enabled` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否启用： true 启用 false 禁用',
  `tenant_id` bigint(20) unsigned NOT NULL COMMENT '商户ID, @link user.id',
  `submitter_id` bigint(20) unsigned DEFAULT NULL COMMENT '提交人ID, @link user.id',
  `submitter_username` varchar(20) DEFAULT NULL COMMENT '提交人, @link user.username',
  `submit_time` datetime(6) DEFAULT NULL COMMENT '提交时间',
  `auditor_id` bigint(20) unsigned DEFAULT NULL COMMENT '审核人ID, @link user.id',
  `auditor_username` varchar(20) DEFAULT NULL COMMENT '审核人, @link user.username',
  `audit_time` datetime(6) DEFAULT NULL COMMENT '审核时间',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注',
  `service_info_id` bigint(20) unsigned DEFAULT NULL COMMENT '客服账号ID @link service_info.id',
  `enable_auth_code` tinyint(1) NOT NULL DEFAULT '0' COMMENT '玩家注册时的校验码是否开启  true： 是 false : 否',
  `enable_img_code` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否启用图形校验码  true： 是 false : 否',
  `enable_show_mobile` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否可以获取会员手机号 true： 是 false : 否',
  `rebate_agent_domain` varchar(255) DEFAULT NULL COMMENT '洗码代理域名',
  `rebate_agent_domain_id` bigint(20) unsigned DEFAULT NULL COMMENT '关联洗码代理的渠道域名中间表ID @link domain.id',
  `pc_template_style_id` bigint(20) unsigned DEFAULT NULL COMMENT 'pc模板风格ID @link plat_template_style.id',
  `h5_template_style_id` bigint(20) unsigned DEFAULT NULL COMMENT 'h5模板风格ID @link plat_template_style.id',
  `cocos_template_style_id` bigint(20) DEFAULT NULL COMMENT 'cocos模板风格ID @link plat_template_style.id',
  `pc_icon` varchar(250) DEFAULT NULL COMMENT '链接头icon图标',
  `h5_icon` varchar(250) DEFAULT NULL COMMENT '链接头icon图标',
  `pc_icon_name` varchar(250) DEFAULT NULL COMMENT 'PWA图标',
  `h5_icon_name` varchar(250) DEFAULT NULL COMMENT 'PC icon名字',
  `app_photo_name` varchar(250) DEFAULT NULL COMMENT 'PWA图标 名字',
  `pc_title` varchar(250) DEFAULT NULL COMMENT '链接头说明',
  `h5_title` varchar(250) DEFAULT NULL COMMENT '链接头说明',
  `app_photo` varchar(250) DEFAULT NULL COMMENT 'PWA图标 名字',
  `auto_regist` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否启用下载自动注册',
  `hand_reg_show` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否开启手动注册弹窗',
  `app_download_flag` tinyint(1) NOT NULL DEFAULT '1' COMMENT 'APP下载开启标识',
  `app_alias_name` varchar(50) DEFAULT NULL COMMENT '数据APP平台名称',
  `type` int(4) DEFAULT '1' COMMENT '平台类型 1、现金网；2、棋牌；3、彩票站；4、体育站',
  `login_skin` int(2) NOT NULL DEFAULT '2' COMMENT '登陆/注册页开关 1:旧皮肤，2:新皮肤',
  `auto_transfer` tinyint(1) NOT NULL DEFAULT '1' COMMENT '自动带入带出，true：是，false：否',
  `agent_h5_material_id` bigint(20) unsigned DEFAULT NULL COMMENT '代理宣传配置h5图片地址',
  `agent_pc_material_id` bigint(20) unsigned DEFAULT NULL COMMENT '代理宣传配置pc图片地址',
  `has_users_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '三方是否有会员体系 flase否 true是',
  `risk_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否开启风控校验：0:默认关闭，1:开启',
  `dividend_agent_domain` varchar(255) DEFAULT NULL COMMENT '分红代理域名',
  `dividend_agent_domain_id` bigint(20) unsigned DEFAULT NULL COMMENT '分红代理的渠道域名中间表ID',
  `h5_img_supplier` int(2) NOT NULL DEFAULT '0' COMMENT '终端是H5的图形验证码供应商：0 腾讯云 ，1 阿里云 ',
  `other_img_supplier` int(2) NOT NULL DEFAULT '0' COMMENT '终端是非H5的图形验证码供应商：0 腾讯云 ，1 阿里云 ',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=106 DEFAULT CHARSET=utf8mb4 COMMENT='商户平台';

CREATE TABLE `game_line_series` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `create_time` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) COMMENT '创建时间',
  `modify_time` datetime(6) DEFAULT NULL COMMENT '修改时间',
  `version` int(11) NOT NULL DEFAULT '1' COMMENT '版本号',
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除： true 删除 false 未删除',
  `series_name` varchar(50) NOT NULL COMMENT '名称',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=62 DEFAULT CHARSET=utf8mb4 COMMENT='游戏线路系列';

CREATE TABLE `game_line` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `create_time` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) COMMENT '创建时间',
  `modify_time` datetime(6) DEFAULT NULL COMMENT '修改时间',
  `version` int(11) NOT NULL DEFAULT '1' COMMENT '版本号',
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除： true 删除 false 未删除',
  `modifier_id` bigint(20) unsigned DEFAULT NULL COMMENT '修改人id @link user.id',
  `modifier_username` varchar(20) DEFAULT NULL COMMENT '修改人',
  `name` varchar(50) NOT NULL COMMENT '名称',
  `code` varchar(50) NOT NULL COMMENT '线路惟一code',
  `enabled` tinyint(1) NOT NULL DEFAULT '0' COMMENT '运营状态： true 启用 false 禁用',
  `game_line_series_id` bigint(20) unsigned NOT NULL COMMENT '游戏线路所属系列Id， @link game_line_series.id',
  `game_line_series_name` varchar(255) NOT NULL COMMENT '游戏线路所属系列名称 @link game_line_series.series_name',
  `manage_url` varchar(255) DEFAULT NULL COMMENT '三方线路后台网址',
  `game_plat_pre` varchar(20) DEFAULT NULL COMMENT '线路前置标识',
  `h5_support` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'h5试玩支持 true ： 是， false : 否',
  `pc_support` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'pc试玩支持 true ： 是， false : 否',
  `h5_open` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'h5试玩开启 true ： 是， false : 否',
  `pc_open` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'pc试玩开启 true ： 是， false : 否',
  `third_lobby` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否连接第三方游戏大厅： true 是， false : 否',
  `ch_name` varchar(50) DEFAULT NULL COMMENT '中文名',
  `screen_flag` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否允许切换屏幕标识： true 是',
  `show_style` int(11) NOT NULL DEFAULT '2' COMMENT '进入游戏显示方式  1，竖屏 2，横屏',
  `sort` int(1) DEFAULT '999' COMMENT '排序',
  `support_iframe` tinyint(1) DEFAULT '0' COMMENT '1 支持, 0 不支持',
  `subscript_material_id` bigint(20) unsigned DEFAULT NULL COMMENT '角标素材id',
  `transfer_flag` tinyint(1) DEFAULT '1' COMMENT '转账开关',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=98 DEFAULT CHARSET=utf8mb4 COMMENT='游戏线路';

CREATE TABLE `game_type` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `create_time` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) COMMENT '创建时间',
  `modify_time` datetime(6) DEFAULT NULL COMMENT '修改时间',
  `version` int(11) NOT NULL DEFAULT '1' COMMENT '版本号',
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除： true 删除 false 未删除',
  `name` varchar(50) NOT NULL COMMENT '名称',
  `electronic` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否为电子 true 是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=15 DEFAULT CHARSET=utf8mb4 COMMENT='游戏类型';

CREATE TABLE `game` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `create_time` datetime(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) COMMENT '创建时间',
  `modify_time` datetime(6) DEFAULT NULL COMMENT '修改时间',
  `version` int(11) NOT NULL DEFAULT '1' COMMENT '版本号',
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除： true 删除 false 未删除',
  `creator_id` bigint(20) unsigned NOT NULL COMMENT '创建人ID, @link user.id',
  `creator_username` varchar(20) NOT NULL COMMENT '创建人, @link user.username',
  `modifier_id` bigint(20) unsigned DEFAULT NULL COMMENT '修改人id @link user.id',
  `modifier_username` varchar(20) DEFAULT NULL COMMENT '修改人',
  `game_line_id` bigint(20) unsigned DEFAULT NULL COMMENT '游戏线路id @link game_line.id',
  `game_type_id` bigint(20) unsigned DEFAULT NULL COMMENT '游戏类型id @link game_type.id',
  `game_line_series_id` bigint(20) unsigned DEFAULT NULL COMMENT '游戏系列id @link game_line_series.id',
  `name` varchar(50) DEFAULT NULL COMMENT '游戏名称',
  `code` varchar(50) DEFAULT NULL COMMENT '游戏标识（现金网）',
  `enable` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否启用  true： 是， false : 否',
  `seq` int(11) NOT NULL DEFAULT '0' COMMENT '序号',
  `recommend` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否推荐  true： 是， false : 否',
  `pc_img_name` varchar(255) DEFAULT NULL COMMENT 'pc展示图片名称',
  `pc_img_url` varchar(255) DEFAULT NULL COMMENT 'pc展示图片路径',
  `h5_img_name` varchar(255) DEFAULT NULL COMMENT 'h5展示图片名称',
  `h5_img_url` varchar(255) DEFAULT NULL COMMENT 'h5展示图片路径',
  `h5_support` tinyint(1) DEFAULT NULL COMMENT '是否支持H5：true 支持，false 不支持',
  `h5_code` varchar(50) DEFAULT NULL COMMENT 'h5进入游戏的code',
  `pc_support` tinyint(1) DEFAULT NULL COMMENT '是否支持PC：true 支持，false 不支持',
  `pc_code` varchar(50) DEFAULT NULL COMMENT 'PC进入游戏 的code',
  `line_num` int(1) NOT NULL DEFAULT '0' COMMENT '线路号码',
  `bet_game_type_id` bigint(20) unsigned DEFAULT NULL COMMENT '游戏注单类型id @link game_type.id',
  `high_bonus_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否高爆： true 是；false 否',
  `high_multiple_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否高倍： true 是；false 否',
  `game_line_seq` int(11) DEFAULT '9999' COMMENT '游戏线路顺序编号',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=31077 DEFAULT CHARSET=utf8mb4 COMMENT='游戏';

CREATE TABLE `bds_bet_order_person_chess_and_card_extend` (
  `id` bigint(20) NOT NULL COMMENT '主键ID',
  `create_time` datetime(6) NOT NULL COMMENT '创建时间',
  `modify_time` datetime(6) DEFAULT NULL COMMENT '修改时间',
  `version` int(11) NOT NULL DEFAULT '1' COMMENT '版本号',
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除：0未删除，1已删除',
  `tenant_id` bigint(20) DEFAULT NULL COMMENT '商户ID, @link user.id',
  `tenant_plat_id` bigint(20) DEFAULT NULL COMMENT '商户平台ID, @link tenant_plat.id',
  `bet_time` datetime(6) NOT NULL COMMENT '下注时间',
  `settle_time` datetime(6) DEFAULT NULL COMMENT '结算时间',
  `game_id` bigint(20) DEFAULT NULL COMMENT '游戏ID, @link game.id',
  `game_line_series_id` bigint(20) DEFAULT NULL COMMENT '游戏线路系列ID, @link game_line_series.id',
  `game_type_id` bigint(20) DEFAULT NULL COMMENT '游戏类型ID, @link game_type.id',
  `bet_game_type_id` bigint(20) DEFAULT NULL COMMENT '投注游戏类型ID, @link game_type.id',
  `channel_id` bigint(20) DEFAULT NULL COMMENT '渠道ID, @link channel.id',
  `player_id` bigint(20) DEFAULT NULL COMMENT '玩家ID, @link player.id',
  `game_line_id` bigint(20) unsigned DEFAULT NULL COMMENT '游戏线路ID, @link game_line.id',
  `game_username` varchar(200) DEFAULT NULL COMMENT '游戏内用户名',
  `third_order_no` varchar(255) NOT NULL COMMENT '三方订单号',
  `bet_order_id` bigint(20) NOT NULL COMMENT '明细表id',
  `settle_status` tinyint(4) DEFAULT NULL COMMENT '结算状态',
  `insurance_win` decimal(19,4) DEFAULT NULL COMMENT '保险盈利',
  `insurance_bet` decimal(19,4) DEFAULT NULL COMMENT '投保额',
  `extend_win_loss_amount` decimal(19,4) DEFAULT NULL COMMENT '玩家输赢',
  `take` decimal(19,4) DEFAULT NULL COMMENT '抽水',
  `extend_valid_bet_amount` decimal(19,4) DEFAULT NULL COMMENT '有效投注',
  `win_loss_amount` decimal(19,4) DEFAULT NULL COMMENT '@link bds_bet_order_detail.win_loss_amount',
  PRIMARY KEY (`id`) /*T![clustered_index] CLUSTERED */,
  KEY `idx_tenant_plat_player` (`tenant_plat_id`,`player_id`),
  KEY `idx_bet_order_id` (`bet_order_id`),
  KEY `idx_third_order_no` (`third_order_no`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin COMMENT='真人棋牌明细扩展表';

CREATE TABLE `bds_bet_order_detail` (
  `id` bigint(20) NOT NULL COMMENT '主键ID',
  `create_time` datetime(6) NOT NULL COMMENT '创建时间',
  `modify_time` datetime(6) DEFAULT NULL COMMENT '修改时间',
  `version` int(11) DEFAULT '1' COMMENT '版本号',
  `deleted` tinyint(1) DEFAULT '0' COMMENT '是否删除：0未删除，1已删除',
  `bet_time` datetime(6) NOT NULL COMMENT '下注时间',
  `settle_time` datetime(6) DEFAULT NULL COMMENT '结算时间',
  `tenant_id` bigint(20) DEFAULT NULL COMMENT '商户ID, @link user.id',
  `tenant_plat_id` bigint(20) DEFAULT NULL COMMENT '商户平台ID, @link tenant_plat.id',
  `player_id` bigint(20) DEFAULT NULL COMMENT '玩家ID, @link player.id',
  `game_id` bigint(20) DEFAULT NULL COMMENT '游戏ID, @link game.id',
  `game_name` text DEFAULT NULL COMMENT '游戏名称',
  `game_line_id` bigint(20) DEFAULT NULL COMMENT '游戏线路ID, @link game_line.id',
  `game_line_series_id` bigint(20) DEFAULT NULL COMMENT '游戏线路系列ID, @link game_line_series.id',
  `game_type_id` bigint(20) DEFAULT NULL COMMENT '游戏类型ID, @link game_type.id',
  `channel_id` bigint(20) DEFAULT NULL COMMENT '渠道ID, @link channel.id',
  `rebate_agent_id` bigint(20) DEFAULT NULL COMMENT '洗码代理ID, @link user.id',
  `third_order_no` varchar(255) DEFAULT NULL COMMENT '三方订单号',
  `settle_status` tinyint(2) DEFAULT NULL COMMENT '结算状态：0未结算，1已结算，2已撤单',
  `bet_amount` decimal(19,4) DEFAULT NULL COMMENT '投注金额',
  `win_loss_amount` decimal(19,4) DEFAULT NULL COMMENT '玩家输赢金额',
  `valid_bet_amount` decimal(19,4) DEFAULT NULL COMMENT '有效投注金额',
  `bet_content` text DEFAULT NULL COMMENT '投注内容',
  `bet_game_type_id` bigint(20) DEFAULT NULL COMMENT '投注游戏类型ID, @link game_type.id',
  `source_type` tinyint(2) DEFAULT NULL COMMENT '数据来源类型：1三方同步，2人工录入',
  `agent_tenant_id` bigint(20) DEFAULT NULL COMMENT '代理商户ID（适配代理体系三方接入）',
  `agent_member_no` varchar(100) DEFAULT NULL COMMENT '代理会员号（适配代理体系三方接入）',
  `agent_member_id` varchar(50) DEFAULT NULL COMMENT '代理会员ID（适配代理体系三方接入）',
  PRIMARY KEY (`id`,`bet_time`) /*T![clustered_index] CLUSTERED */,
  UNIQUE KEY `uni_bet_time_and_game_line_id_and_third_order` (`bet_time`,`game_line_id`,`third_order_no`),
  KEY `idx_agent_tenant_member` (`agent_tenant_id`,`agent_member_no`),
  KEY `idx_bet_order_bt` (`bet_time`),
  KEY `idx_settle_time` (`settle_time`),
  KEY `idx_player_id` (`player_id`),
  KEY `idx_create_time` (`create_time`),
  KEY `idx_third_order_no` (`third_order_no`),
  KEY `idx_modify_time` (`modify_time`),
  KEY `idx_third_order_no_and_game_line_id` (`third_order_no`,`game_line_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin;
